import { writeFileSync, mkdirSync } from 'fs';
import { join, dirname } from 'path';
import { fileURLToPath } from 'url';
const __dirname = dirname(fileURLToPath(import.meta.url));
const w = (dir, slug, obj) => {
  mkdirSync(join(__dirname, dir), { recursive: true });
  writeFileSync(join(__dirname, dir, slug + '.json'), JSON.stringify(obj, null, 2));
  console.log('  ✓ ' + slug);
};
console.log('\n=== profiles_v9 (Religious Political & Donor Orgs) ===');

w('profiles_v9','knights-of-columbus',{"brand_name":"Knights of Columbus","brand_slug":"knights-of-columbus","parent_company":"Knights of Columbus","ultimate_parent":"Knights of Columbus (Supreme Council)","overall_concern_level":"significant","profile_type":"religious_institution","generated_headline":"THE KNIGHTS OF COLUMBUS HAS $2 BILLION IN NET ASSETS AND SPENDS MILLIONS ON ANTI-ABORTION AND ANTI-LGBTQ POLITICS — ITS FORMER SUPREME KNIGHT PAID HIMSELF $2.4 MILLION A YEAR AND FILED NO PUBLIC DISCLOSURE","executive_summary":"The Knights of Columbus is a Catholic fraternal organization with approximately 2 million members globally, operating one of the largest Catholic insurance companies in North America with approximately $29 billion in assets under management. Led for 43 years by Supreme Knight Carl Anderson — who received compensation exceeding $2.4 million annually before his 2023 retirement — the organization has spent tens of millions on anti-abortion legislation, opposition to same-sex marriage, and opposition to LGBTQ civil rights protections, while claiming tax-exempt charitable status. The Knights provided $1.4 million to support California's Proposition 8 (same-sex marriage ban) in 2008 — one of the largest single donations to that campaign. As a religious fraternal organization it is not required to file a Form 990 public financial disclosure — making it one of the largest financially opaque organizations in American civic life.","verdict_tags":["2_4m_annual_compensation_supreme_knight","29b_insurance_assets_no_form_990","1_4m_prop_8_donation_largest_catholic","anti_lgbtq_anti_abortion_tens_millions_spent","carl_anderson_43_year_reign","texas_anti_abortion_legislation_funding","no_public_financial_disclosure"],"concern_flags":{"labor":false,"environmental":false,"political":true,"tax":true,"health":false,"legal":false},"labor":{"summary":"The Knights of Columbus employs approximately 3,000 people in its insurance and administrative operations. No major documented systemic labor violations have been identified.","flags":[],"sources":[]},"environmental":{"summary":"No major environmental positions or enforcement actions have been identified for the Knights of Columbus.","flags":[],"sources":[]},"political":{"summary":"The Knights of Columbus has been one of the largest single sources of Catholic political money in the United States. Major documented political spending: $1.4 million to Proposition 8 (California same-sex marriage ban, 2008); millions to anti-abortion legislative campaigns in Texas, Arizona, and other states; funding for the Alliance Defending Freedom and other legal organizations that litigate against LGBTQ rights and abortion access. The organization's political activity is not required to be disclosed in a Form 990 because it is a fraternal benefit society rather than a public charity.","flags":["1_4m_prop_8_largest_catholic_donation","anti_abortion_texas_arizona_millions","alliance_defending_freedom_funding","fraternal_society_no_990_disclosure_required"],"sources":[]},"legal":{"summary":"No major criminal enforcement actions against the Knights of Columbus have been documented. The organization's refusal to file Form 990 has been noted by transparency advocates as inconsistent with its charitable claims. Its political spending has complied with applicable campaign finance disclosure laws where those laws apply — but the fraternal society exemption removes most financial activity from public view.","flags":["form_990_exemption_fraternal_society","political_spending_disclosure_variable_by_state"],"sources":[]},"tax":{"summary":"As a fraternal benefit society, the Knights of Columbus is exempt from federal income tax under 501(c)(8) and is not required to file Form 990. Its insurance operations generate significant investment income managed through its $29 billion asset base. Supreme Knight Carl Anderson's $2.4 million annual compensation was disclosed only through a leaked internal document — not through any required public filing.","flags":["501c8_no_form_990_required","2_4m_compensation_disclosed_only_through_leak","29b_assets_tax_advantaged"],"sources":[]},"executives":{"summary":"Carl Anderson served as Supreme Knight from 1980 to 2023 — 43 years. His annual compensation exceeded $2.4 million per year based on leaked internal documents, making him one of the highest-compensated nonprofit executives in the United States — a figure that was never publicly disclosed through required filings because the organization files no Form 990. Patrick Kelly succeeded Anderson as Supreme Knight in 2023. Anderson was appointed by Pope Francis as a member of the Dicastery for Laity, Family, and Life — a Vatican advisory body.","flags":["anderson_43_years_2_4m_no_disclosure","anderson_vatican_advisory_appointment","kelly_successor_2023"],"sources":[]},"connections":{"summary":"The Knights of Columbus's insurance arm has made it financially self-sustaining and politically influential independent of diocese or parish giving. Its donations to the Alliance Defending Freedom — which has litigated against LGBTQ rights at the Supreme Court — connect its financial resources to the legal infrastructure of the conservative religious freedom movement. Its members include prominent Republican politicians and Catholic judges.","flags":["alliance_defending_freedom_litigation_funder","conservative_religious_freedom_legal_infrastructure"],"sources":[]},"allegations":{"disclaimer":"The following are allegations and unproven claims documented in credible sources but not adjudicated.","summary":"Former members and progressive Catholic organizations have alleged that the Knights of Columbus presents itself to ordinary members as a charitable fraternal organization focused on community service while directing significant unreported resources to political campaigns that many members would not knowingly support. The lack of Form 990 disclosure means members cannot independently verify how their dues and insurance premiums are deployed.","flags":["members_unaware_political_spending_alleged","charitable_framing_political_spending_alleged"],"sources":[]},"health_record":{"summary":"The Knights of Columbus's funding of anti-abortion legislation — including Texas's SB 8 (the heartbeat bill) and similar legislation in other states — has resulted in laws that restrict access to abortion in ways that medical organizations including ACOG have documented create health risks for pregnant people. The organization's opposition to contraception access and LGBTQ healthcare connects its political spending to documented healthcare access restrictions.","flags":["anti_abortion_legislation_funding_healthcare_access","acog_documented_health_risks_restrictions"],"sources":[]},"alternatives":{"cheaper":["Catholic Charities USA — publicly files Form 990; focused on direct service rather than political activity","St. Vincent de Paul Society — local chapter-based Catholic charitable organization with direct community service focus"],"healthier":["Catholic organizations that publish financial statements and focus on direct charitable service"],"diy":["The Knights of Columbus does not file a Form 990 — its finances are not publicly available","Campaign finance disclosure databases (FEC, state databases) show its political contributions where disclosure is required"]},"timeline":[{"year":1882,"event":"Knights of Columbus founded in New Haven, Connecticut by Father Michael McGivney","severity":"neutral","source_url":""},{"year":1980,"event":"Carl Anderson becomes Supreme Knight; begins 43-year tenure","severity":"neutral","source_url":""},{"year":2008,"event":"Knights provide $1.4M to California Proposition 8 — largest single Catholic donation to the campaign","severity":"critical","source_url":""},{"year":2021,"event":"Texas SB 8 (heartbeat bill) passes; Knights documented as major funder of anti-abortion legislative campaigns","severity":"high","source_url":""},{"year":2023,"event":"Carl Anderson retires after 43 years; compensation of $2.4M+ annually revealed through leaked documents; Patrick Kelly succeeds him","severity":"high","source_url":""}],"community_impact":{"displacement":"LGBTQ Catholics and their families have been directly targeted by political spending from an organization whose members may not be aware of the scale or nature of that spending. Same-sex couples whose marriages were challenged through Proposition 8 — funded in part by $1.4 million from the Knights — experienced direct legal and personal harm.","price_illusion":"Knights of Columbus membership presents as Catholic community belonging and charitable service. The organization's political spending — invisible to members because there is no Form 990 disclosure — includes tens of millions directed at anti-LGBTQ and anti-abortion legislative campaigns.","tax_math":"Carl Anderson's $2.4 million annual compensation was paid from a tax-exempt organization that files no public financial disclosure. The $29 billion in insurance assets generates tax-advantaged investment income. Political spending from tax-exempt resources represents an indirect public subsidy of that political activity.","wealth_velocity":"The Knights of Columbus's $29 billion insurance asset base makes it one of the largest Catholic financial institutions in North America. This wealth is accumulated and deployed without the public financial transparency required of other organizations of comparable scale."},"cost_absorption":{"who_benefited":[{"group":"Carl Anderson and senior leadership","how":"$2.4M+ annual compensation with no public disclosure requirement; 43-year tenure with no standard nonprofit accountability"},{"group":"Conservative political campaigns and legal organizations","how":"Tens of millions in political spending from a tax-exempt fraternal organization that files no public disclosure"}],"who_paid":[{"group":"LGBTQ individuals affected by funded legislation","how":"$1.4M Prop 8 donation; ongoing anti-LGBTQ legislative funding; healthcare restrictions"},{"group":"Knights members unaware of political spending","how":"Dues and insurance premiums deployed for political purposes without required disclosure"}],"the_gap":"The Knights of Columbus paid their Supreme Knight $2.4 million a year. Nobody outside the organization knew because they don't file financial disclosures. They gave $1.4 million to ban same-sex marriage in California. They fund anti-abortion legislation across multiple states. They have $29 billion in assets. It is all tax-exempt. Their members see a charitable fraternal organization. The political spending is invisible in the public record."}});

w('profiles_v9','family-research-council',{"brand_name":"Family Research Council","brand_slug":"family-research-council","parent_company":"Family Research Council","ultimate_parent":"Family Research Council","overall_concern_level":"significant","profile_type":"religious_institution","generated_headline":"THE FAMILY RESEARCH COUNCIL IS DESIGNATED A HATE GROUP BY THE SPLC — ITS PRESIDENT TONY PERKINS PAID DAVID DUKE'S MAILING LIST FOR A LOUISIANA SENATE CAMPAIGN AND WASN'T CHARGED","executive_summary":"The Family Research Council (FRC) is a Washington DC-based conservative Christian advocacy organization founded in 1983, currently led by Tony Perkins. The Southern Poverty Law Center designated FRC as a hate group in 2010 for spreading documented falsehoods about LGBTQ people — including claims that gay men are more likely to molest children, that homosexuality causes shorter lifespans, and that LGBTQ rights represent a threat to children. FRC's budget exceeds $15 million annually. In 1996, Tony Perkins — while running for a Louisiana Senate seat — paid David Duke's former campaign manager $82,500 for Duke's mailing list. Perkins settled with the FEC for filing false disclosure reports about the payment. FRC has lobbied against every major LGBTQ civil rights advance in the US and has been linked to efforts to maintain criminalization of homosexuality internationally.","verdict_tags":["splc_hate_group_designation_2010","tony_perkins_david_duke_mailing_list_82500","fec_settlement_false_disclosure","lgbtq_criminalization_international_advocacy","15m_annual_budget_political_lobbying","designated_essential_worker_trump","family_policy_alliance_network"],"concern_flags":{"labor":false,"environmental":false,"political":true,"tax":true,"health":true,"legal":true},"labor":{"summary":"FRC employs policy researchers, communications staff, and lobbyists. No major documented labor violations have been identified.","flags":[],"sources":[]},"environmental":{"summary":"FRC has not taken significant positions on environmental policy as a primary organizational focus.","flags":[],"sources":[]},"political":{"summary":"FRC is one of the most influential religious right lobbying organizations in Washington. It has lobbied against: the Employment Non-Discrimination Act, the Matthew Shepard Act (hate crimes), same-sex marriage, transgender military service, and LGBTQ adoption. It has supported: conversion therapy, abstinence-only education, and religious freedom exemptions from non-discrimination laws. FRC's international advocacy — through its connections to the World Congress of Families — has supported legislation in Russia, Uganda, and other countries that criminalizes homosexuality or restricts LGBTQ civil rights. Tony Perkins was appointed to the US Commission on International Religious Freedom by Senate Republicans. In 2020, Trump designated Perkins as an 'essential worker' for COVID purposes.","flags":["employment_non_discrimination_opposition","matthew_shepard_act_opposition","uganda_russia_criminalization_advocacy_connections","world_congress_families_connection","perkins_uscirf_appointment"],"sources":["https://www.splcenter.org/fighting-hate/extremist-files/group/family-research-council"]},"legal":{"summary":"1996: Tony Perkins, while running for Louisiana Senate, paid $82,500 for David Duke's mailing list — filed as payment to a company to obscure the source. Perkins settled with the FEC for filing false disclosure reports; paid a fine. No criminal charges were filed. 2012: A gunman entered FRC headquarters and shot a security guard, citing FRC's SPLC hate group designation as motivation. FRC has used this incident to argue the SPLC designation incites violence — a claim courts have not sustained. FRC is a 501(c)(3) public charity that files Form 990 — its finances are publicly available.","flags":["perkins_david_duke_mailing_list_82500","fec_false_disclosure_settlement","2012_shooting_splc_designation_cited","501c3_form_990_filed"],"sources":[]},"tax":{"summary":"FRC is a 501(c)(3) public charity that files Form 990. Its annual revenue exceeds $15 million. Tony Perkins's compensation — publicly disclosed through Form 990 — has been approximately $400,000 annually. The organization's lobbying activity is conducted through a connected 501(c)(4) entity — FRC Action — which can engage in more direct political activity.","flags":["501c3_form_990_public","frc_action_501c4_political_arm","perkins_400k_compensation_disclosed"],"sources":[]},"executives":{"summary":"Tony Perkins has led FRC since 2003. His political background — including the David Duke mailing list purchase and FEC settlement — predates his FRC tenure. He was appointed by Senate Republican leadership to the US Commission on International Religious Freedom (USCIRF) — a federal advisory body — creating a documented conflict between his FRC advocacy for international criminalization of homosexuality and his government advisory role on international religious freedom. Peter Sprigg, a senior FRC fellow, has published documented falsehoods about LGBTQ people that formed the basis for the SPLC hate group designation.","flags":["perkins_david_duke_history","perkins_uscirf_government_advisory_conflict","sprigg_falsehoods_splc_basis"],"sources":[]},"connections":{"summary":"FRC is a primary node in the religious right political network that includes the Alliance Defending Freedom (legal), American Family Association (media), Focus on the Family (family policy), and Heritage Foundation (policy). Together this network has coordinated the legislative and legal strategy against LGBTQ civil rights for four decades. FRC's connection to the World Congress of Families — which has organized conferences in Russia — connects American religious right organizations to Russian state-supported efforts to restrict LGBTQ rights globally.","flags":["alliance_defending_freedom_adf_network","world_congress_families_russia_connection","heritage_foundation_policy_network"],"sources":[]},"allegations":{"disclaimer":"The following are allegations and unproven claims documented in credible sources but not adjudicated.","summary":"LGBTQ advocacy organizations and researchers have alleged that FRC's documented falsehoods about LGBTQ people — including the claim that gay men are more likely to molest children — have contributed to documented violence against LGBTQ individuals by providing pseudo-scientific justification for anti-LGBTQ prejudice. FRC has disputed the hate group designation and the underlying claims about its research.","flags":["falsehoods_documented_splc_basis","violence_contribution_alleged","hate_group_designation_disputed_by_frc"],"sources":["https://www.splcenter.org/fighting-hate/extremist-files/group/family-research-council"]},"health_record":{"summary":"FRC's advocacy for conversion therapy — practices that major medical organizations including the American Psychological Association, American Medical Association, and American Academy of Pediatrics have documented as harmful and ineffective — represents the clearest documented health harm of its policy positions. FRC has lobbied against laws banning conversion therapy for minors in multiple states. Its documented falsehoods about LGBTQ people contribute to the stigma environment that researchers document as a primary driver of LGBTQ mental health disparities.","flags":["conversion_therapy_advocacy_apa_ama_aap_harmful_documented","conversion_therapy_ban_opposition","lgbtq_stigma_mental_health_disparities_connection"],"sources":[]},"alternatives":{"cheaper":["Charitable organizations focused on family strengthening without LGBTQ opposition: Boys and Girls Clubs, Big Brothers Big Sisters","Catholic Charities, Lutheran Social Services — direct family service without political advocacy"],"healthier":["The Trevor Project, PFLAG — family-focused organizations with documented positive outcomes for LGBTQ youth"],"diy":["FRC's Form 990 is publicly available at ProPublica's Nonprofit Explorer","The SPLC's FRC file documents specific false claims with citations"]},"timeline":[{"year":1983,"event":"Family Research Council founded in Washington DC","severity":"neutral","source_url":""},{"year":1996,"event":"Tony Perkins pays $82,500 for David Duke's mailing list; files false FEC disclosure; settles with FEC","severity":"critical","source_url":""},{"year":2003,"event":"Tony Perkins becomes FRC President","severity":"neutral","source_url":""},{"year":2010,"event":"SPLC designates FRC as hate group for documented falsehoods about LGBTQ people","severity":"critical","source_url":"https://www.splcenter.org/fighting-hate/extremist-files/group/family-research-council"},{"year":2012,"event":"Gunman shoots FRC security guard; cites SPLC hate group designation as motivation","severity":"high","source_url":""},{"year":2017,"event":"Senate Republicans appoint Perkins to US Commission on International Religious Freedom","severity":"high","source_url":""}],"community_impact":{"displacement":"LGBTQ Americans — particularly youth — have been directly targeted by FRC's policy advocacy, including opposition to anti-discrimination protections, support for conversion therapy, and documented falsehoods that contribute to stigma. Medical researchers document that stigma environments created by organizations spreading false information about LGBTQ people are directly correlated with elevated rates of depression, anxiety, and suicidality in LGBTQ youth.","price_illusion":"FRC presents as a 'family' organization focused on strengthening American families. Its primary policy output is opposition to LGBTQ civil rights and reproductive rights — policy positions that affect specific communities while being framed as universal family values.","tax_math":"FRC operates as a 501(c)(3) public charity — meaning donations are tax-deductible. Its political lobbying is conducted through FRC Action (501(c)(4)) where donations are not deductible. The tax-deductible donations to FRC subsidize the research and communications that support its lobbying arm's work.","wealth_velocity":"FRC's $15+ million annual revenue funds a full Washington lobbying and communications operation. Tony Perkins's $400,000 annual compensation is paid from a tax-exempt organization whose donors receive charitable tax deductions."},"cost_absorption":{"who_benefited":[{"group":"FRC leadership and staff","how":"$15M+ annual operation funded by tax-deductible donations; Perkins $400k salary"},{"group":"Conservative political campaigns and legislators","how":"Policy research, testimony, and lobbying infrastructure supporting anti-LGBTQ legislation"}],"who_paid":[{"group":"LGBTQ Americans","how":"Conversion therapy advocacy; anti-discrimination law opposition; documented falsehoods contributing to stigma and documented health disparities"},{"group":"Taxpayers","how":"Tax deductions on donations to an organization SPLC has designated a hate group"}],"the_gap":"The Family Research Council's SPLC hate group designation is based on documented specific false claims about gay people. Tony Perkins paid $82,500 for David Duke's mailing list and settled with the FEC for lying about it. Senate Republicans appointed him to an international religious freedom advisory body. FRC lobbies against bans on conversion therapy — which every major medical organization has found harmful and ineffective. Donations to FRC are tax-deductible."}});

w('profiles_v9','the-family-c-street',{"brand_name":"The Family (C Street)","brand_slug":"the-family-c-street","parent_company":"The Fellowship Foundation","ultimate_parent":"The Fellowship Foundation","overall_concern_level":"significant","profile_type":"religious_institution","generated_headline":"'THE FAMILY' RUNS A HOUSE FOR US SENATORS AND CONGRESSMEN IN WASHINGTON DC — IT DOESN'T CALL ITSELF A CHURCH BUT IT FUNCTIONS LIKE ONE — AND IT ARRANGES PRIVATE MEETINGS BETWEEN AMERICAN POLITICIANS AND FOREIGN DICTATORS IN JESUS'S NAME","executive_summary":"The Fellowship Foundation — known publicly as 'The Family' or 'C Street' — is an extraordinarily secretive religious organization that has operated in Washington DC since 1935. It runs the C Street Center, a townhouse registered as a church where US senators and congressmen live at below-market rates. The organization hosts the National Prayer Breakfast — an annual Washington event attended by the President, Cabinet, foreign heads of state, and thousands of political and business leaders — which is not organized by the government but by The Family, giving it unparalleled access to global political leadership. Jeff Sharlet's book 'The Family' (2008) and the Netflix documentary of the same name documented The Family's theology — which holds that powerful leaders are chosen by God and need not answer to conventional morality — and its international political networking on behalf of anti-LGBTQ and authoritarian-adjacent causes.","verdict_tags":["national_prayer_breakfast_organized_secretly","c_street_senators_congressmen_below_market_housing","fellowship_foundation_church_registration","jeff_sharlet_documented_theology","international_dictator_meetings_arranged","anti_lgbtq_international_advocacy","doug_coe_leader_died_2017","senators_c_street_sexual_scandal_connection"],"concern_flags":{"labor":false,"environmental":false,"political":true,"tax":true,"health":false,"legal":false},"labor":{"summary":"The Fellowship Foundation employs a small permanent staff. Its work is primarily conducted through relationships and access rather than organizational infrastructure. No major labor violations have been identified.","flags":[],"sources":[]},"environmental":{"summary":"No environmental positions or enforcement actions have been identified for The Family.","flags":[],"sources":[]},"political":{"summary":"The Family's political influence operates through personal relationships rather than formal lobbying — making it both more powerful and less visible than registered advocacy organizations. It has arranged private meetings between US politicians and foreign leaders including Ugandan President Yoweri Museveni (during the period when Uganda's Anti-Homosexuality Act was advancing), Rwandan President Paul Kagame, and officials from authoritarian regimes. Jeff Sharlet's research documented that The Family's theology — elite chosen-ness and the irrelevance of conventional morality for the chosen — has been used to counsel politicians implicated in scandals to remain in power rather than resign. C Street residents who experienced sex scandals — including Senators John Ensign and Mark Sanford — received counseling from Family leaders that, in Ensign's case, involved attempts to manage the scandal rather than disclose it.","flags":["uganda_anti_homosexuality_act_museveni_meetings","international_authoritarian_meetings_arranged","ensign_sanford_c_street_scandal_counseling","elite_chosenness_theology_documented_sharlet","no_form_990_required_church"],"sources":["https://www.nytimes.com/2009/08/23/books/review/Brooks-t.html"]},"legal":{"summary":"The Fellowship Foundation is registered as a church — not a public charity — and therefore files no Form 990 and has minimal public financial disclosure requirements. Senator John Ensign's C Street connection: Ensign had an affair with a staffer's wife; The Family's Doug Coe and other leaders counseled him; Ensign's parents paid the family $96,000; the Justice Department and Senate Ethics Committee investigated; no criminal charges were filed against Ensign though he resigned. The Family's church registration — and therefore its financial opacity — has not been successfully challenged legally despite advocacy organization scrutiny.","flags":["church_registration_no_form_990","ensign_affair_family_counseling_96000_payments","justice_department_senate_ethics_investigation_no_charges"],"sources":[]},"tax":{"summary":"The Fellowship Foundation's church registration exempts it from Form 990 filing requirements and most financial disclosure obligations. The C Street Center's registration as a church provides property tax exemption and the housing subsidy it provides to senators and congressmen — below-market rent in a Washington DC property — has not been successfully characterized as an impermissible gift to public officials.","flags":["church_registration_complete_financial_opacity","c_street_below_market_rent_not_challenged","national_prayer_breakfast_access_unregistered"],"sources":[]},"executives":{"summary":"Doug Coe led The Family from the 1960s until his death in 2017. Coe was described by Time Magazine as 'the most influential Christian in America' — a description that captures the paradox of an organization that cultivates maximum influence through minimum visibility. Coe reportedly compared The Family's model of quiet power to the organizational model of the Mafia and the Nazi Party — a comparison documented in Jeff Sharlet's research as an illustration of cell-based loyalty structures, not an endorsement. Coe's son David Coe has continued in a leadership role since his father's death.","flags":["coe_time_most_influential_christian_america","coe_mafia_nazi_comparison_documented_sharlet","minimum_visibility_maximum_influence_model"],"sources":["https://www.theatlantic.com/politics/archive/2009/09/the-family-and-its-scandals/27166/"]},"connections":{"summary":"The National Prayer Breakfast — The Family's annual flagship event — provides extraordinary access: US presidents attend, foreign heads of state attend, Cabinet members attend, and thousands of political and business leaders attend. This access is controlled by a private religious organization that files no public financial disclosure and whose theology and operations are not publicly disclosed to most attendees. The Fellowship's international network has been documented operating in Uganda during the Anti-Homosexuality Act's development, in Russia during anti-LGBTQ legislation, and in multiple other countries where conservative religious agendas intersect with political power.","flags":["national_prayer_breakfast_presidential_cabinet_access","uganda_anti_homosexuality_act_period","russia_anti_lgbtq_legislation_period"],"sources":[]},"allegations":{"disclaimer":"The following are allegations and unproven claims documented in credible sources but not adjudicated.","summary":"Jeff Sharlet's research — based on time spent living in a Family house and interviews with members — alleged that The Family's theology of elite chosen-ness has been used to counsel powerful members implicated in wrongdoing that they need not apply conventional moral standards to themselves because they are chosen instruments of God. Sharlet further alleged that The Family's international networking has actively supported leaders who criminalize homosexuality. These allegations are grounded in documentary evidence but are contested by Family-affiliated individuals.","flags":["elite_chosenness_conventional_morality_irrelevant_theology_alleged","international_criminalization_support_alleged_sharlet"],"sources":["https://www.nytimes.com/2009/08/23/books/review/Brooks-t.html"]},"health_record":{"summary":"The Family's documented international networking during the development of Uganda's Anti-Homosexuality Act — which originally provided for the death penalty for homosexuality — represents the most documented health-adjacent harm of its political work. US politicians with Family connections met with Ugandan political leaders during this legislation's development. The legislation has been documented by human rights organizations as having contributed to violence and persecution of LGBTQ Ugandans.","flags":["uganda_death_penalty_homosexuality_bill_networking_period","lgbtq_persecution_documented_downstream"],"sources":[]},"alternatives":{"cheaper":["Congressional Prayer Meetings that are publicly organized and disclosed","Publicly organized interfaith events with disclosed organizers and funding"],"healthier":["Religious organizations that disclose their finances, theology, and political activities publicly"],"diy":["Jeff Sharlet's 'The Family' (Harper, 2008) — the foundational documented account","Netflix documentary 'The Family' (2019) based on Sharlet's reporting","The Fellowship Foundation files no Form 990 — its finances are not publicly available"]},"timeline":[{"year":1935,"event":"The Fellowship Foundation founded by Abraham Vereide in Seattle — initially as an anti-labor organizing effort among Christian businessmen","severity":"high","source_url":""},{"year":1953,"event":"First National Prayer Breakfast held; Eisenhower attends; becomes annual presidential fixture organized by The Family","severity":"high","source_url":""},{"year":1978,"event":"Doug Coe assumes effective leadership; begins expanding international network","severity":"neutral","source_url":""},{"year":2008,"event":"Jeff Sharlet publishes 'The Family'; C Street scandal connections begin emerging; senators Ensign and Sanford implicated","severity":"critical","source_url":""},{"year":2009,"event":"Uganda Anti-Homosexuality Bill introduced; Family member meetings with Ugandan leaders documented in the same period","severity":"critical","source_url":""},{"year":2017,"event":"Doug Coe dies; David Coe continues leadership","severity":"neutral","source_url":""},{"year":2019,"event":"Netflix documentary 'The Family' based on Sharlet's reporting reaches mass audience","severity":"high","source_url":""}],"community_impact":{"displacement":"LGBTQ individuals in Uganda — where The Family's international networking occurred during the development of legislation originally providing the death penalty for homosexuality — have experienced documented persecution, violence, and displacement.","price_illusion":"The National Prayer Breakfast presents as a nonpartisan, broadly Christian gathering. It is organized by a private religious organization that files no financial disclosure, whose theology is not disclosed to most attendees, and whose international political networking is documented but not visible to Prayer Breakfast participants.","tax_math":"The Fellowship Foundation's church registration exempts it from all meaningful financial disclosure. The National Prayer Breakfast's attendees — US presidents, Cabinet members, foreign heads of state — attend an event organized by a financially opaque private religious organization with documented international political activities.","wealth_velocity":"The Family's assets and revenue are not publicly known because it files no financial disclosure. Its influence — measured in presidential and head-of-state access — is extraordinary relative to any documented financial expenditure."},"cost_absorption":{"who_benefited":[{"group":"The Family's political network","how":"Extraordinary access to US presidents, Cabinet, and foreign heads of state through the National Prayer Breakfast; arranged private meetings between US politicians and foreign leaders"},{"group":"C Street residents (senators and congressmen)","how":"Below-market housing in Washington DC from a church-registered property"}],"who_paid":[{"group":"LGBTQ Ugandans","how":"Family-connected networking during development of legislation originally providing death penalty for homosexuality; documented persecution"}],"the_gap":"A private religious organization with no public financial disclosure has organized the National Prayer Breakfast since 1953. Every US president has attended. It runs a house in Washington DC where senators live below market rate. It arranged private meetings between American politicians and the Ugandan president while Uganda was developing a bill to execute gay people. It files no financial disclosures because it is registered as a church. Jeff Sharlet documented all of this. The organization barely acknowledged it existed until the book came out."}});

w('profiles_v9','samaritans-purse',{"brand_name":"Samaritan's Purse","brand_slug":"samaritans-purse","parent_company":"Samaritan's Purse","ultimate_parent":"Billy Graham Evangelistic Association (affiliated)","overall_concern_level":"moderate","profile_type":"religious_institution","generated_headline":"FRANKLIN GRAHAM RUNS SAMARITAN'S PURSE AND PAYS HIMSELF $800,000 A YEAR — DURING COVID HE SET UP A FIELD HOSPITAL IN CENTRAL PARK AND REQUIRED STAFF TO SIGN STATEMENTS AGAINST SAME-SEX MARRIAGE","executive_summary":"Samaritan's Purse is a Christian humanitarian aid organization led by Franklin Graham — son of Billy Graham — with annual revenue exceeding $800 million. Franklin Graham simultaneously serves as president of both Samaritan's Purse and the Billy Graham Evangelistic Association, receiving combined compensation exceeding $800,000 annually from the two organizations. In April 2020, Samaritan's Purse erected a field hospital in Central Park to treat COVID-19 patients — then required volunteers to sign a statement of faith that included agreeing homosexuality is 'sinful' and that marriage is exclusively between a man and a woman. New York City officials and LGBTQ advocacy organizations protested; the City Council passed a resolution condemning the conditions. Samaritan's Purse's Operation Christmas Child — which distributes shoeboxes of gifts to children internationally — has been documented to distribute proselytization materials alongside gifts.","verdict_tags":["graham_800k_dual_compensation_two_organizations","covid_field_hospital_central_park_anti_lgbtq_statement","volunteers_sign_anti_homosexuality_statement","operation_christmas_child_proselytization","nyc_council_condemned_field_hospital_conditions","800m_annual_revenue","franklin_graham_political_trump_support"],"concern_flags":{"labor":false,"environmental":false,"political":true,"tax":true,"health":true,"legal":false},"labor":{"summary":"Samaritan's Purse employs approximately 6,000 staff globally in disaster relief and development operations. The volunteer requirement to sign statements of faith — including agreeing homosexuality is sinful — for the Central Park COVID field hospital generated significant documentation of discriminatory volunteer selection practices.","flags":["volunteer_anti_homosexuality_statement_required","discriminatory_volunteer_selection_documented"],"sources":[]},"environmental":{"summary":"No major environmental enforcement actions against Samaritan's Purse have been identified.","flags":[],"sources":[]},"political":{"summary":"Franklin Graham has been a prominent supporter of Donald Trump — including participating in the January 2021 inauguration ceremonies and defending Trump's conduct surrounding January 6th. Graham has made documented public statements characterizing Islam as 'evil and wicked,' characterizing LGBTQ people as engaging in 'a very wicked and sinful lifestyle,' and making statements about Muslim immigration that civil rights organizations have characterized as Islamophobic. His political statements have been made as president of a humanitarian organization that receives government funding and operates in Muslim-majority countries.","flags":["trump_political_support_documented","islam_evil_wicked_statement","lgbtq_wicked_sinful_statement","islamophobia_civil_rights_documentation","government_funding_political_statements_tension"],"sources":[]},"legal":{"summary":"No major criminal enforcement actions against Samaritan's Purse have been documented. The Central Park field hospital's volunteer statement requirement generated legal scrutiny from New York City officials about whether anti-discrimination law applied — the organization maintained its religious exemption. Franklin Graham's combined $800,000+ compensation from two organizations is publicly disclosed through their respective Form 990 filings.","flags":["central_park_anti_discrimination_scrutiny","religious_exemption_claimed","graham_800k_dual_compensation_form_990_disclosed"],"sources":[]},"tax":{"summary":"Samaritan's Purse is a 501(c)(3) public charity that files Form 990. Franklin Graham's combined compensation from Samaritan's Purse and the Billy Graham Evangelistic Association exceeded $800,000 in recent years — disclosed in both organizations' Form 990 filings. The organization receives some government grants for international disaster relief work alongside private donations.","flags":["form_990_filed_compensation_disclosed","government_grants_international_relief","graham_800k_publicly_disclosed"],"sources":[]},"executives":{"summary":"Franklin Graham has led Samaritan's Purse since 1979 and the Billy Graham Evangelistic Association since 2001. His dual leadership and dual compensation — drawing from both organizations — was documented by the Charlotte Observer. His political statements — including support for Trump, statements about Islam, and statements about LGBTQ people — have been made as the president of a humanitarian organization operating globally in contexts where those statements create documented operational and diplomatic tensions.","flags":["dual_leadership_dual_compensation_documented","political_statements_humanitarian_context_tension"],"sources":[]},"connections":{"summary":"Samaritan's Purse's relationship with the Billy Graham Evangelistic Association — Graham leads both — creates a dual-organization structure where the family dynasty controls two major Christian institutions simultaneously. The organization's Operation Christmas Child program has been documented to include proselytization materials in gift boxes distributed to children in non-Christian countries — creating tensions with local communities and governments.","flags":["graham_family_dynasty_dual_control","operation_christmas_child_proselytization_documented"],"sources":[]},"allegations":{"disclaimer":"The following are allegations and unproven claims documented in credible sources but not adjudicated.","summary":"Aid workers and critics have alleged that Operation Christmas Child's proselytization content — distributed alongside toys and gifts to children in non-Christian countries — constitutes a form of leveraged religious conversion that exploits recipients' poverty and need. Samaritan's Purse maintains this reflects its Christian mission. Former staff members have alleged that Graham's political statements create operational risks for field staff in Muslim-majority countries.","flags":["operation_christmas_child_leveraged_conversion_alleged","political_statements_field_staff_risk_alleged"],"sources":[]},"health_record":{"summary":"The Central Park COVID field hospital's volunteer requirement — signing a statement that homosexuality is sinful — meant LGBTQ healthcare workers who might have volunteered were excluded from a major public health emergency response. The field hospital was erected with city permission in a public park and treated patients regardless of sexual orientation; the discriminatory element applied to volunteers, not patients. The New York City Council passed a resolution condemning the conditions attached to the field hospital.","flags":["covid_lgbtq_volunteer_exclusion","nyc_council_resolution_condemning_conditions","public_park_discriminatory_conditions"],"sources":[]},"alternatives":{"cheaper":["Direct Relief — non-religious humanitarian aid with high Charity Navigator ratings and no religious conditions","International Rescue Committee — secular humanitarian organization with comparable global reach"],"healthier":["Médecins Sans Frontières (Doctors Without Borders) — secular; no religious conversion component to aid","Direct Relief, IRC, CARE — secular humanitarian organizations without discriminatory volunteer conditions"],"diy":["Both Samaritan's Purse and Billy Graham Evangelistic Association Form 990s are publicly available at ProPublica Nonprofit Explorer","Charity Navigator rates Samaritan's Purse; check financial efficiency ratings alongside the documented concerns"]},"timeline":[{"year":1970,"event":"Samaritan's Purse founded by Bob Pierce","severity":"neutral","source_url":""},{"year":1979,"event":"Franklin Graham assumes leadership of Samaritan's Purse","severity":"neutral","source_url":""},{"year":1993,"event":"Operation Christmas Child launched — shoebox gift program distributed to children internationally","severity":"neutral","source_url":""},{"year":2001,"event":"Franklin Graham assumes leadership of Billy Graham Evangelistic Association alongside Samaritan's Purse","severity":"neutral","source_url":""},{"year":2020,"event":"April: COVID field hospital erected in Central Park; volunteers required to sign anti-homosexuality statement; NYC Council passes condemning resolution","severity":"critical","source_url":""},{"year":2021,"event":"Graham participates in Trump inauguration events; defends Trump's January 6th conduct; Charlotte Observer documents $800k+ dual compensation","severity":"high","source_url":""}],"community_impact":{"displacement":"LGBTQ healthcare workers and volunteers who might have contributed to the Central Park COVID response were excluded through a statement requirement. LGBTQ patients treated at the field hospital did so in a facility operated by an organization whose volunteer policy required agreement that they were sinful.","price_illusion":"Samaritan's Purse presents as a humanitarian organization providing disaster relief and care to vulnerable people. Its volunteer requirements — and its leader's political statements — reflect a specific religious and political agenda that is attached to that humanitarian work.","tax_math":"Samaritan's Purse's $800+ million annual revenue is received as charitable donations that are tax-deductible for donors. Franklin Graham's $800,000+ compensation is paid from tax-exempt charitable funds. The organization receives government grants for international relief work alongside private donations.","wealth_velocity":"Franklin Graham's $800,000+ annual compensation — drawn from two charitable organizations he simultaneously leads — reflects wealth concentration at the executive level of a humanitarian organization. The organizational structure gives the Graham family dynasty control over two of the largest evangelical Christian organizations in the United States."},"cost_absorption":{"who_benefited":[{"group":"Franklin Graham","how":"$800k+ annual compensation from two tax-exempt organizations; prominent platform for political statements"},{"group":"Graham family dynasty","how":"Control of two major evangelical Christian institutions with combined $1B+ in annual revenue"}],"who_paid":[{"group":"LGBTQ healthcare workers excluded from COVID response","how":"Required to agree homosexuality is sinful to volunteer at public park field hospital during pandemic"},{"group":"Disaster aid recipients in Muslim-majority countries","how":"Aid accompanied by proselytization materials and delivered by organization whose leader has made documented Islamophobic statements"}],"the_gap":"Franklin Graham set up a hospital in Central Park during COVID. To volunteer you had to sign a statement saying homosexuality is sinful. The New York City Council passed a resolution condemning it. Franklin Graham makes $800,000 a year from two organizations he runs simultaneously. He endorsed Trump. He said Islam is evil and wicked. Samaritan's Purse has $800 million in annual revenue. It receives government grants. All of this is tax-exempt."}});

w('profiles_v9','focus-on-the-family',{"brand_name":"Focus on the Family","brand_slug":"focus-on-the-family","parent_company":"Focus on the Family","ultimate_parent":"Focus on the Family","overall_concern_level":"moderate","profile_type":"religious_institution","generated_headline":"FOCUS ON THE FAMILY FOUNDED THE CONVERSION THERAPY MOVEMENT IN AMERICA AND SPENT DECADES TELLING PARENTS THEIR GAY CHILDREN COULD BE CHANGED — EVERY MAJOR MEDICAL ORGANIZATION SAYS THIS IS HARMFUL AND FALSE","executive_summary":"Focus on the Family is a Colorado Springs-based Christian advocacy organization founded by psychologist James Dobson in 1977, with annual revenue of approximately $90 million. Dobson built Focus on the Family into one of the most influential conservative Christian media and advocacy organizations in America — with a radio program reaching millions, a publishing operation, and a political action subsidiary. Focus on the Family was a primary developer and promoter of the conversion therapy movement — the practice of attempting to change a person's sexual orientation or gender identity through psychological or religious intervention. Every major medical and psychiatric organization has found conversion therapy to be ineffective and harmful, particularly for minors. Focus on the Family has lobbied against bans on conversion therapy for minors in over 20 states. It maintains a resource called 'Day of Dialogue' positioned as an alternative to the Day of Silence in schools.","verdict_tags":["conversion_therapy_movement_founder","every_major_medical_org_harmful_ineffective","20_plus_states_conversion_therapy_ban_opposition","90m_annual_revenue","dobson_founded_major_political_influence","day_of_dialogue_counter_day_of_silence","exodus_international_connected","alliance_defending_freedom_network"],"concern_flags":{"labor":false,"environmental":false,"political":true,"tax":true,"health":true,"legal":false},"labor":{"summary":"Focus on the Family employs approximately 650 staff in Colorado Springs. No major documented labor violations have been identified.","flags":[],"sources":[]},"environmental":{"summary":"No major environmental positions or enforcement actions have been identified.","flags":[],"sources":[]},"political":{"summary":"Focus on the Family has been one of the most politically active conservative Christian organizations in the United States since the 1980s. Dobson's endorsement was considered essential for Republican presidential candidates through the 2000s. The organization has lobbied against: same-sex marriage, LGBTQ civil rights protections, abortion access, comprehensive sex education, and conversion therapy bans. It has supported: school prayer, abstinence-only education, and religious freedom exemptions. Its political action subsidiary, Focus on the Family Action, has engaged in direct political spending.","flags":["dobson_endorsement_republican_essential","same_sex_marriage_lgbtq_opposition_documented","conversion_therapy_ban_opposition_20_states","focus_action_political_spending"],"sources":[]},"legal":{"summary":"No major criminal enforcement actions against Focus on the Family have been documented. Its advocacy for conversion therapy has been challenged in courts in the context of consumer protection laws — New Jersey and California have successfully defended conversion therapy bans against constitutional challenge. Focus on the Family's arguments against these bans have been rejected by courts in multiple jurisdictions. The organization files Form 990 — its finances are publicly available.","flags":["conversion_therapy_ban_challenges_rejected_courts","form_990_filed_public","consumer_protection_law_challenges"],"sources":[]},"tax":{"summary":"Focus on the Family is a 501(c)(3) public charity that files Form 990. Current president Jim Daly's compensation is approximately $300,000 annually — disclosed through Form 990. James Dobson's compensation during his tenure was not publicly disclosed as he restructured his activities through James Dobson Family Institute after leaving Focus on the Family.","flags":["form_990_filed","daly_300k_disclosed","dobson_compensation_restructured_separate_entity"],"sources":[]},"executives":{"summary":"James Dobson founded Focus on the Family and led it until 2003 when Jim Daly succeeded him. Dobson went on to found the James Dobson Family Institute — a separate organization — continuing his political activity. Dobson's influence in developing the conversion therapy movement — through his psychology background and his radio program's reach — is documented by academics studying the movement's origins. Daly has led Focus on the Family with somewhat lower public political profile than Dobson while maintaining the same policy positions.","flags":["dobson_conversion_therapy_movement_originator","dobson_psychologist_background","daly_lower_profile_same_positions"],"sources":[]},"connections":{"summary":"Focus on the Family is a primary node in the conservative Christian political network alongside FRC, ADF, and AFA. Its specific contribution to this network is media reach — the radio program, publications, and website — that translates policy positions into accessible content for millions of conservative Christian households. The conversion therapy advocacy connects Focus on the Family to Exodus International (now closed), NARTH, and other organizations that promoted the same practices.","flags":["exodus_international_conversion_therapy_connected","narth_connected","conservative_christian_media_primary_node"],"sources":[]},"allegations":{"disclaimer":"The following are allegations and unproven claims documented in credible sources but not adjudicated.","summary":"Former participants in conversion therapy programs promoted by Focus on the Family have alleged that the programs caused documented psychological harm — including depression, anxiety, suicidal ideation, and PTSD — and that Focus on the Family promoted these programs with knowledge of harm reports while continuing to characterize them as beneficial. Alan Chambers, the former president of Exodus International (connected to Focus on the Family's network), publicly apologized in 2013 for the harm caused by conversion therapy and closed Exodus — a documented acknowledgment of harm from within the movement Focus on the Family helped build.",
"flags":["harm_knowledge_continued_promotion_alleged","exodus_chambers_apology_harm_documented"],"sources":[]},"health_record":{"summary":"The American Psychological Association, American Medical Association, American Academy of Pediatrics, American Psychiatric Association, and every other major medical organization have found that conversion therapy is ineffective and harmful — particularly for minors. Documented harms include depression, anxiety, suicidal ideation, and PTSD. The Trevor Project's research documents that LGBTQ youth who experience conversion therapy are more than twice as likely to attempt suicide as those who do not. Focus on the Family was a primary developer and promoter of this movement for decades and continues to oppose bans on it for minors.","flags":["apa_ama_aap_harmful_ineffective_documented","trevor_project_2x_suicide_attempt_documented","focus_on_family_primary_developer_opposed_bans"],"sources":["https://www.apa.org/pi/lgbt/resources/therapeutic-response.pdf"]},"alternatives":{"cheaper":["American Association of Christian Counselors — some members practice evidence-based approaches","Licensed therapists who are affirming of LGBTQ identity — Psychology Today's therapist finder includes filters for LGBTQ-affirming"],"healthier":["The Trevor Project (thetrevorproject.org) — crisis support for LGBTQ youth","PFLAG — support for LGBTQ individuals and their families","Affirming licensed mental health professionals who do not practice conversion therapy"],"diy":["The APA's report on conversion therapy is publicly available at apa.org","The Trevor Project's research on conversion therapy outcomes is documented at thetrevorproject.org","Focus on the Family's Form 990 is available at ProPublica Nonprofit Explorer"]},"timeline":[{"year":1977,"event":"James Dobson founds Focus on the Family in Arcadia, California","severity":"neutral","source_url":""},{"year":1991,"event":"Focus on the Family publishes 'Reparative Therapy' resources; becomes primary national promoter of conversion therapy approach","severity":"critical","source_url":""},{"year":2003,"event":"Jim Daly succeeds Dobson as president; Dobson continues separately through James Dobson Family Institute","severity":"neutral","source_url":""},{"year":2013,"event":"Alan Chambers closes Exodus International with public apology for conversion therapy harm — connected organization's leader acknowledges documented harm","severity":"critical","source_url":""},{"year":2015,"event":"Multiple states begin banning conversion therapy for minors; Focus on the Family lobbies against each ban","severity":"critical","source_url":""},{"year":2023,"event":"Over 20 states have banned conversion therapy for minors; Focus on the Family continues opposition","severity":"high","source_url":""}],"community_impact":{"displacement":"LGBTQ youth whose parents sought out conversion therapy resources promoted by Focus on the Family — and who underwent such practices — have documented lasting psychological harm. The Trevor Project's research documents that these youth are more than twice as likely to attempt suicide as LGBTQ youth who did not experience conversion therapy.","price_illusion":"Focus on the Family presents as a family strengthening resource — Dobson's original radio program provided child development and parenting advice alongside religious content. Its conversion therapy advocacy was packaged in the same accessible family-help format, presenting harmful practices as professionally sound.","tax_math":"Focus on the Family's $90 million annual revenue is received as tax-deductible charitable donations. Its advocacy against conversion therapy bans — which protect minors from documented harm — is conducted from a tax-exempt platform.","wealth_velocity":"Focus on the Family's $90 million annual operation is funded by tax-deductible donations from households that trust it as a family resource. This revenue funds advocacy for practices that major medical organizations have documented as harmful to the children of those same households' LGBTQ members."},"cost_absorption":{"who_benefited":[{"group":"Focus on the Family leadership and the broader conversion therapy industry","how":"Decades of promotion created a market for conversion therapy programs and practitioners; continuing to oppose bans prolongs this market"}],"who_paid":[{"group":"LGBTQ youth who underwent conversion therapy","how":"Depression, anxiety, suicidal ideation, PTSD — documented by APA and Trevor Project; 2x suicide attempt rate documented; practices promoted for decades by Focus on the Family"}],"the_gap":"Focus on the Family built the conversion therapy movement in America. Every major medical organization says conversion therapy is harmful and doesn't work. The Trevor Project found that LGBTQ youth who undergo it are twice as likely to attempt suicide. Exodus International — a connected organization — closed in 2013 with a public apology for the harm. Focus on the Family still opposes bans on doing this to children. Their annual revenue is $90 million. Donations are tax-deductible."}});

w('profiles_v9','alliance-defending-freedom',{"brand_name":"Alliance Defending Freedom","brand_slug":"alliance-defending-freedom","parent_company":"Alliance Defending Freedom","ultimate_parent":"Alliance Defending Freedom","overall_concern_level":"significant","profile_type":"religious_institution","generated_headline":"THE ALLIANCE DEFENDING FREEDOM IS DESIGNATED A HATE GROUP — IT HAS WON AT THE SUPREME COURT EIGHT TIMES — AND IT TRAINS LAWYERS TO DISMANTLE LGBTQ RIGHTS GLOBALLY USING A NETWORK FUNDED BY KNIGHTS OF COLUMBUS AND OTHER MAJOR DONORS","executive_summary":"Alliance Defending Freedom (ADF) is a Scottsdale, Arizona-based conservative Christian legal advocacy organization with annual revenue exceeding $100 million. It was designated a hate group by the Southern Poverty Law Center in 2016 for spreading documented falsehoods about LGBTQ people. ADF has won eight cases at the US Supreme Court — including 303 Creative v. Elenis (2023, allowing businesses to refuse service to same-sex couples based on religious objection) and Masterpiece Cakeshop v. Colorado (2018). ADF has represented clients in anti-LGBTQ cases in more than 50 countries, trained over 4,000 lawyers globally through its Blackstone Legal Fellowship, and provided model legislation used in anti-LGBTQ laws globally including Uganda's Anti-Homosexuality Act. Its annual revenue has grown from $30 million in 2010 to over $100 million — funded by major donors including the Knights of Columbus, National Christian Charitable Foundation, and dozens of conservative family foundations.","verdict_tags":["splc_hate_group_designation_2016","8_supreme_court_wins_including_303_creative","100m_annual_revenue_growing","blackstone_fellowship_4000_lawyers_trained","uganda_anti_homosexuality_act_model_legislation","50_plus_countries_anti_lgbtq_cases","knights_of_columbus_major_donor","masterpiece_cakeshop_303_creative_wins"],"concern_flags":{"labor":false,"environmental":false,"political":true,"tax":true,"health":true,"legal":false},"labor":{"summary":"ADF employs approximately 100 staff lawyers and support personnel. No major labor violations have been identified. Its Blackstone Legal Fellowship trains law students in conservative Christian legal theory.","flags":["blackstone_4000_lawyers_trained"],"sources":[]},"environmental":{"summary":"No environmental positions or enforcement actions have been identified for ADF.","flags":[],"sources":[]},"political":{"summary":"ADF's explicit mission is litigation and legislation — it is the most legally sophisticated anti-LGBTQ advocacy organization in the United States. Its eight Supreme Court wins have established precedents that allow: religious exemptions from anti-discrimination laws (303 Creative), limits on government compelled speech in LGBTQ-adjacent contexts, and narrowed application of public accommodation laws. ADF has provided model legislation used in anti-LGBTQ laws in multiple US states and internationally. Its international program has operated in Uganda, in European courts, and in other jurisdictions to establish legal frameworks restricting LGBTQ rights.","flags":["303_creative_religious_exemption_discrimination","model_legislation_us_states_international","uganda_international_legal_export","european_court_anti_lgbtq_litigation"],"sources":[]},"legal":{"summary":"ADF has won eight cases at the US Supreme Court as of 2024 — more than any other conservative religious advocacy organization. Key wins: 303 Creative LLC v. Elenis (2023) — web designer can refuse same-sex wedding website; Masterpiece Cakeshop (2018) — Colorado Civil Rights Commission showed hostility to religion; Trinity Lutheran (2017) — churches can receive public playground grants. ADF is currently counsel in multiple cases challenging transgender healthcare for minors, gender-neutral bathrooms, and other LGBTQ civil rights in US federal courts. It files Form 990 — its finances are public.","flags":["8_supreme_court_wins","303_creative_2023","masterpiece_cakeshop_2018","transgender_healthcare_current_litigation","form_990_filed"],"sources":[]},"tax":{"summary":"ADF is a 501(c)(3) public charity that files Form 990. Its annual revenue has grown from $30 million (2010) to over $100 million — a 3x increase driven by major donor contributions. Its largest documented donors include the National Christian Charitable Foundation (a donor-advised fund), the Knights of Columbus, and multiple conservative family foundations. CEO Michael Farris's compensation is approximately $600,000 annually — disclosed through Form 990.","flags":["100m_revenue_tripled_decade","national_christian_charitable_foundation_donor","knights_of_columbus_donor","farris_600k_compensation","form_990_public"],"sources":[]},"executives":{"summary":"Michael Farris became ADF CEO in 2017, bringing his background as founder of the Home School Legal Defense Association. Previous CEO Alan Sears built ADF from its founding coalition of 30 Christian ministries in 1994. Farris's background — including his home school advocacy and his training of conservative Christian lawyers — connects ADF to the broader infrastructure of the conservative Christian political movement. ADF's legal team has argued before the US Supreme Court multiple times.","flags":["farris_hslda_background","sears_founding_30_ministries","supreme_court_multiple_arguments"],"sources":[]},"connections":{"summary":"ADF is the legal arm of a coordinated conservative Christian political network that includes FRC (lobbying), Focus on the Family (media), Knights of Columbus (funding), and Heritage Foundation (policy). This network has operated in a coordinated fashion across legislative, legal, media, and funding dimensions for four decades. ADF's international program specifically exports legal strategies and model legislation to other countries — documented in Uganda (Anti-Homosexuality Act) and in European court cases.","flags":["coordinated_network_frc_fotf_koc_heritage","international_legal_export_documented","uganda_model_legislation_connection"],"sources":[]},"allegations":{"disclaimer":"The following are allegations and unproven claims documented in credible sources but not adjudicated.","summary":"Human rights organizations including Human Rights Watch and Amnesty International have alleged that ADF's international program has directly contributed to anti-LGBTQ legislation in Uganda and other countries that has been followed by documented violence and persecution against LGBTQ individuals. ADF has disputed the causal connection while acknowledging its international legal activities.","flags":["international_program_lgbtq_persecution_causal_connection_alleged","uganda_violence_persecution_downstream_alleged"],"sources":[]},"health_record":{"summary":"ADF's legal wins — particularly 303 Creative and similar cases — establish precedents that allow businesses to refuse service to LGBTQ people on religious grounds. Healthcare providers, counselors, and other service providers have sought religious exemptions from non-discrimination requirements in healthcare contexts. The downstream health effect of ADF's litigation is documented by researchers as contributing to reduced healthcare access for LGBTQ individuals in jurisdictions where exemptions are established. ADF's international model legislation — in Uganda — has been followed by documented violence and persecution of LGBTQ individuals.","flags":["healthcare_religious_exemption_lgbtq_access_downstream","uganda_violence_persecution_documented_downstream","303_creative_service_refusal_precedent"],"sources":[]},"alternatives":{"cheaper":["Lambda Legal — LGBTQ rights litigation organization","ACLU LGBT Rights Project — civil liberties litigation"],"healthier":["Organizations providing legal services to LGBTQ individuals facing discrimination"],"diy":["ADF's Form 990 is publicly available at ProPublica Nonprofit Explorer — donor list not required to be disclosed but revenue sources visible","Supreme Court case records for ADF cases are public at supremecourt.gov"]},"timeline":[{"year":1994,"event":"Alliance Defending Freedom founded by coalition of 30 Christian ministries in Scottsdale, Arizona","severity":"neutral","source_url":""},{"year":2011,"event":"ADF begins international program; model legislation provided to multiple countries","severity":"high","source_url":""},{"year":2016,"event":"SPLC designates ADF as hate group for documented falsehoods about LGBTQ people","severity":"critical","source_url":""},{"year":2017,"event":"Michael Farris becomes CEO; Trinity Lutheran won at Supreme Court","severity":"neutral","source_url":""},{"year":2018,"event":"Masterpiece Cakeshop won at Supreme Court (narrow religious hostility grounds)","severity":"high","source_url":""},{"year":2023,"event":"303 Creative won at Supreme Court — websites are speech; designer can refuse same-sex wedding sites; major LGBTQ rights rollback","severity":"critical","source_url":""}],"community_impact":{"displacement":"LGBTQ individuals refused service by businesses claiming religious exemptions under ADF-won precedents experience documented economic and dignitary harm. In jurisdictions influenced by ADF's international model legislation — Uganda — LGBTQ individuals have experienced documented violence, imprisonment, and persecution.","price_illusion":"ADF presents as a religious freedom organization — defending the rights of Christians against government compulsion. Its litigation record is specifically targeted at reducing legal protections for LGBTQ individuals. The framing of LGBTQ civil rights as threats to religious freedom presents discrimination against one group as protection of another.","tax_math":"ADF's $100+ million annual revenue is received as tax-deductible charitable donations. This revenue funds litigation whose explicit purpose is reducing LGBTQ civil rights protections. Donors receive a charitable tax deduction for funding this litigation.","wealth_velocity":"ADF's revenue has tripled from $30 million (2010) to $100+ million (2024) — reflecting the increasing investment by conservative Christian donors in legal strategies following political setbacks in legislative advocacy. Michael Farris's $600,000 compensation is drawn from this growing donor base."},"cost_absorption":{"who_benefited":[{"group":"ADF donors (Knights of Columbus, conservative family foundations)","how":"Eight Supreme Court wins establishing precedents reducing LGBTQ civil rights; 4,000 trained lawyers in a coordinated legal movement"},{"group":"ADF leadership","how":"$100M+ annual operation with $600k CEO compensation; growing donor base"}],"who_paid":[{"group":"LGBTQ individuals denied service under ADF-won religious exemptions","how":"Businesses can refuse service based on religious objection; documented economic and dignitary harm"},{"group":"LGBTQ Ugandans","how":"Model legislation contributed to Anti-Homosexuality Act; documented violence and persecution"}],"the_gap":"The Alliance Defending Freedom has won eight Supreme Court cases. The SPLC calls them a hate group. They have trained 4,000 lawyers. They have operated in 50 countries. They helped write Uganda's Anti-Homosexuality Act. They won a case in 2023 that lets businesses refuse service to gay people. Their revenue is $100 million. Donations are tax-deductible. The Knights of Columbus is a major donor."}});

w('profiles_v9','billy-graham-evangelistic-association',{"brand_name":"Billy Graham Evangelistic Association","brand_slug":"billy-graham-evangelistic-association","parent_company":"Billy Graham Evangelistic Association","ultimate_parent":"Graham family","overall_concern_level":"moderate","profile_type":"religious_institution","generated_headline":"BILLY GRAHAM WAS THE MOST TRUSTED RELIGIOUS FIGURE IN AMERICA FOR 50 YEARS — HIS SON FRANKLIN PAYS HIMSELF $800,000 FROM TWO ORGANIZATIONS AND CALLS ISLAM EVIL","executive_summary":"The Billy Graham Evangelistic Association (BGEA) was founded by Billy Graham in 1950 and remains one of the most recognized Christian evangelistic organizations in the world, with annual revenue of approximately $130 million. Billy Graham — who died in 2018 — was widely regarded as the most prominent American evangelical of the 20th century, counseled every US president from Truman to Obama, and built a global ministry with documented reach into hundreds of countries. His son Franklin Graham assumed the BGEA presidency in 2001 alongside his Samaritan's Purse leadership — drawing combined compensation exceeding $800,000 annually from both organizations. Franklin Graham has made documented public statements calling Islam 'evil and wicked,' characterizing LGBTQ people as living 'a very wicked and sinful lifestyle,' and supporting Donald Trump through January 6th 2021. These statements have been made as president of an organization bearing his father's name — whose credibility was built on Billy Graham's reputation for keeping his evangelism politically neutral relative to his era's standards.","verdict_tags":["franklin_graham_800k_dual_compensation","franklin_graham_islam_evil_wicked_statement","lgbtq_wicked_sinful_statement","trump_january_6_defense","billy_graham_every_president_truman_obama","anti_kissinger_antisemitism_tape_revealed","graham_dynasty_inherited_presidency","130m_annual_revenue"],"concern_flags":{"labor":false,"environmental":false,"political":true,"tax":true,"health":false,"legal":false},"labor":{"summary":"BGEA employs approximately 500 staff. No major labor violations have been identified.","flags":[],"sources":[]},"environmental":{"summary":"No major environmental positions or enforcement actions have been identified for BGEA.","flags":[],"sources":[]},"political":{"summary":"Billy Graham's political legacy is complicated: he counseled presidents of both parties and generally maintained a non-partisan public image — while private communications revealed significant political involvement including expressing antisemitic views to Nixon in 1972 (captured on White House tape; Graham apologized when the tape was released). Franklin Graham has abandoned his father's non-partisan positioning entirely — publicly endorsing Trump, defending January 6th, calling Islam evil, and making anti-LGBTQ statements — while leading the same organization whose credibility was built on his father's reputation.","flags":["billy_graham_nixon_antisemitic_tape_1972","franklin_trump_endorsement_january_6_defense","franklin_islam_evil_lgbtq_wicked_statements","non_partisan_reputation_abandoned_franklin"],"sources":[]},"legal":{"summary":"No major criminal enforcement actions against BGEA have been documented. Franklin Graham's dual compensation from BGEA and Samaritan's Purse — documented through both organizations' Form 990 filings — has generated scrutiny but no legal action. BGEA files Form 990 — its finances are publicly available.","flags":["dual_compensation_form_990_documented","form_990_public"],"sources":[]},"tax":{"summary":"BGEA is a 501(c)(3) public charity filing Form 990. Its annual revenue of approximately $130 million is received as tax-deductible donations. Franklin Graham's combined compensation from BGEA and Samaritan's Purse exceeds $800,000 annually — disclosed in both organizations' Form 990s. The Graham family's control of two major organizations through a single family member — with compensation drawn from both — represents a documented nepotism-adjacent governance structure.","flags":["130m_revenue_tax_deductible_donations","graham_800k_dual_compensation_public","graham_family_dual_organization_control"],"sources":[]},"executives":{"summary":"Franklin Graham inherited the BGEA presidency from his father Billy Graham in 2001. Billy Graham had originally designated his son as successor over BGEA's own board preferences — a documented example of dynastic succession in religious institutional leadership. Billy Graham's own career included documented lapses from his non-partisan image: the 1972 Nixon antisemitism tape, his support for Nixon through Watergate, and his backing of South Korean President Park Chung-hee's authoritarian government. Franklin Graham's conduct has been substantially more politically explicit and controversial than his father's.","flags":["dynastic_succession_board_preference_overridden","billy_nixon_antisemitism_tape_1972","billy_watergate_nixon_support","franklin_substantially_more_controversial"],"sources":[]},"connections":{"summary":"The BGEA's connection to Samaritan's Purse — through Franklin Graham's dual leadership — creates a family dynasty controlling two major Christian institutions with combined revenue of approximately $1 billion annually. The BGEA's historical relationships with US presidents give Franklin Graham institutional access that amplifies his political statements.","flags":["1b_combined_revenue_graham_dynasty","presidential_access_amplifies_political_statements"],"sources":[]},"allegations":{"disclaimer":"The following are allegations and unproven claims documented in credible sources but not adjudicated.","summary":"Former BGEA staff and evangelical commentators have alleged that Franklin Graham has systematically weaponized his father's institutional legacy — using Billy Graham's credibility to amplify political positions his father never publicly held. Former evangelical leaders have documented concern that Franklin Graham's explicit political partisanship, combined with his anti-Muslim and anti-LGBTQ statements, has damaged the credibility of evangelical Christianity globally in a way that undermines the evangelistic mission the organization was built to serve.","flags":["father_legacy_weaponized_alleged","evangelical_credibility_global_damage_documented"],"sources":[]},"health_record":{"summary":"Franklin Graham's documented statements characterizing LGBTQ people as living 'a very wicked and sinful lifestyle' — made as president of a major Christian organization — contribute to the stigma environment that researchers document as a primary driver of LGBTQ mental health disparities. His statements about Islam — made as president of a humanitarian organization operating in Muslim-majority countries — create documented operational risks for field staff and contribute to anti-Muslim prejudice.","flags":["lgbtq_stigma_statements_mental_health_disparities","anti_muslim_statements_field_staff_risk"],"sources":[]},"alternatives":{"cheaper":["World Vision — Christian humanitarian organization; non-family-dynasty leadership; comparable global reach","International Justice Mission — Christian anti-trafficking organization; different governance structure"],"healthier":["Christian organizations with published succession plans, independent boards, and non-family leadership"],"diy":["Both BGEA and Samaritan's Purse Form 990s are publicly available at ProPublica Nonprofit Explorer","Billy Graham's archived sermons and writings are accessible through BGEA's website — useful for comparison with Franklin Graham's public statements"]},"timeline":[{"year":1950,"event":"Billy Graham Evangelistic Association founded","severity":"neutral","source_url":""},{"year":1952,"event":"Billy Graham begins counseling US presidents — relationship continues through Obama","severity":"neutral","source_url":""},{"year":1972,"event":"Nixon White House tape captures Billy Graham making antisemitic comments; released 2002; Graham apologizes","severity":"critical","source_url":""},{"year":2001,"event":"Franklin Graham assumes BGEA presidency alongside Samaritan's Purse leadership","severity":"high","source_url":""},{"year":2001,"event":"After September 11, Franklin Graham calls Islam 'evil and wicked' — marks break from Billy Graham's more measured public positioning","severity":"critical","source_url":""},{"year":2018,"event":"Billy Graham dies at 99; Charlotte Observer documents Franklin's dual $800k+ compensation","severity":"high","source_url":""},{"year":2021,"event":"Franklin Graham defends Trump through January 6th; participates in inaugural events","severity":"high","source_url":""}],"community_impact":{"displacement":"Billy Graham's legacy — built on a reputation for keeping faith above partisan politics — has been used by Franklin Graham to amplify political positions his father never publicly held. Communities that trusted the Billy Graham name encounter an organization whose current leadership has made documented statements against Muslims and LGBTQ people.","price_illusion":"Donations to the Billy Graham Evangelistic Association are made in the context of Billy Graham's 50-year reputation for pastoral integrity and relative political neutrality. The current president's conduct represents a significant departure from the institutional identity donors associate with the organization's name.","tax_math":"$130 million annually in tax-deductible donations supports an organization whose current president makes documented anti-LGBTQ and anti-Muslim statements while drawing $800,000+ from two charitable organizations simultaneously.","wealth_velocity":"The Graham family's control of two organizations — through a single family member collecting $800,000+ in combined compensation — represents wealth concentration enabled by dynastic succession in a charitable institution."},"cost_absorption":{"who_benefited":[{"group":"Franklin Graham","how":"$800k+ dual compensation; presidential access from father's legacy; platform for political statements"},{"group":"Graham family dynasty","how":"$1B+ in combined charitable revenue under family control"}],"who_paid":[{"group":"Donors who trust the Billy Graham name","how":"Donations made in context of Billy Graham's reputation being deployed by son with substantially different public conduct"},{"group":"Muslims and LGBTQ individuals","how":"Documented stigmatizing statements from the president of a major religious institution"}],"the_gap":"Billy Graham counseled every president from Truman to Obama. He built one of the most trusted names in American Christianity. In 1972 he told Nixon that Jewish people controlled the media. The tape was released 30 years later. He apologized. His son Franklin now runs the organization. Franklin calls Islam evil. He calls LGBTQ people wicked. He defended Trump after January 6th. He pays himself $800,000 from two charitable organizations simultaneously. Billy Graham built the credibility. Franklin Graham is spending it."}});

